// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract TokenContract is ReentrancyGuard {
    string public name;
    string public symbol;
    uint8 public immutable decimals = 9;
    uint256 public totalSupply;
    mapping(address => uint256) public balances;
    mapping(address => bool) public isExcludedFromFee;
    uint256 public maxTxAmount;
    uint256 public devFee;
    uint256 public rewardsFee;
    address public devAddress;
    address public rewardsAddress;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event FeesChanged(uint256 devFee, uint256 rewardsFee);
    event OnSwapAndRedirectEthFees(address indexed sender, uint256 ethAmount);

    modifier onlyOwner() {
        require(msg.sender == tx.origin, "Only owner can call this function");
        _;
    }

    constructor(
        string memory _name,
        string memory _symbol,
        uint256 _totalSupply,
        uint256 _maxTxAmount,
        uint256 _devFee,
        uint256 _rewardsFee,
        address _devAddress,
        address _rewardsAddress
    ) {
        name = _name;
        symbol = _symbol;
        totalSupply = _totalSupply * (10 ** uint256(decimals));
        maxTxAmount = _maxTxAmount * (10 ** uint256(decimals));
        devFee = _devFee;
        rewardsFee = _rewardsFee;
        devAddress = _devAddress;
        rewardsAddress = _rewardsAddress;
        balances[msg.sender] = totalSupply;
        emit Transfer(address(0), msg.sender, totalSupply);
    }

    function transfer(address recipient, uint256 amount) external nonReentrant returns (bool) {
        require(amount > 0, "Transfer amount must be greater than zero");
        require(amount <= maxTxAmount, "Transfer amount exceeds the maxTxAmount");
        require(balances[msg.sender] >= amount, "Insufficient balance");

        uint256 feeAmount = calculateFee(amount);
        require(balances[msg.sender] >= feeAmount, "Insufficient balance for fees");
        uint256 transferAmount = amount - feeAmount;

        // Update balances in one operation
        balances[msg.sender] -= amount;
        balances[recipient] += transferAmount;
        balances[devAddress] += (feeAmount * devFee) / 100;
        balances[rewardsAddress] += (feeAmount * rewardsFee) / 100;

        emit Transfer(msg.sender, recipient, transferAmount);
        emit Transfer(msg.sender, devAddress, (feeAmount * devFee) / 100);
        emit Transfer(msg.sender, rewardsAddress, (feeAmount * rewardsFee) / 100);
        emit OnSwapAndRedirectEthFees(msg.sender, feeAmount);

        return true;
    }

    function calculateFee(uint256 amount) internal view returns (uint256) {
        uint256 totalFees = devFee + rewardsFee;
        if (isExcludedFromFee[msg.sender]) {
            return 0;
        }
        return (amount * totalFees) / 100;
    }

    function setMaxTxPercent(uint256 percent) external onlyOwner {
        maxTxAmount = (totalSupply * percent) / 10000;
        emit FeesChanged(devFee, rewardsFee);
    }

    function excludeFromFee(address account) external onlyOwner {
        isExcludedFromFee[account] = true;
    }

    function swapAndRedirectEthFees(address sender, uint256 feeAmount) internal nonReentrant {
        uint256 devFeeAmount = (feeAmount * devFee) / 100;
        uint256 rewardsFeeAmount = (feeAmount * rewardsFee) / 100;

        balances[sender] -= feeAmount;
        balances[devAddress] += devFeeAmount;
        balances[rewardsAddress] += rewardsFeeAmount;

        emit OnSwapAndRedirectEthFees(sender, feeAmount);
    }
}
